sequence_1 = ""
sequence_2 = ""

mutation_counter = 0

for i in range(0, len(sequence_1)):
    if sequence_1[i] == "A" and sequence_2[i] == "A":
        continue
    elif sequence_1[i] == "C" and sequence_2[i] == "C":
        continue
    elif sequence_1[i] == "G" and sequence_2[i] == "G":
        continue
    elif sequence_1[i] == "T" and sequence_2[i] == "T":
        continue
    else:
        mutation_counter += 1

print(mutation_counter)